/**
 * BNCP News UI Patch
 *
 * Add this before </body> in index.html:
 *   <script src="./assets/news-patch.js" defer></script>
 *
 * This patch makes the Domestic/Overseas/SNS/COM buttons load static JSON files
 * generated by GitHub Actions.
 */

(function () {
  const CATEGORY_FILES = {
    domestic: "./data/domestic-news.json",
    overseas: "./data/overseas-news.json",
    sns: "./data/sns-news.json",
    com: "./data/com-news.json"
  };

  const CATEGORY_LABELS = {
    domestic: "국내 언론",
    overseas: "해외 언론",
    sns: "SNS",
    com: "COM"
  };

  function normalizeText(el) {
    return (el?.textContent || el?.innerText || "")
      .replace(/\s+/g, "")
      .toLowerCase();
  }

  function detectCategory(el) {
    const idClassData = [
      el.id,
      el.className,
      el.dataset?.category,
      el.dataset?.newsCategory,
      el.getAttribute?.("data-filter")
    ].join(" ").toLowerCase();

    const text = normalizeText(el);

    if (/domestic|korea|kr|국내|국내언론/.test(idClassData) || text.includes("국내")) return "domestic";
    if (/overseas|global|world|foreign|해외|해외언론/.test(idClassData) || text.includes("해외")) return "overseas";
    if (/sns|social|소셜/.test(idClassData) || text.includes("sns")) return "sns";
    if (/com|cabinet|council|مجلس/.test(idClassData) || text.includes("com")) return "com";
    return null;
  }

  function getAllCandidateButtons() {
    return Array.from(document.querySelectorAll("button, a, [role='button'], .tab, .filter, .category, [data-category], [data-news-category]"));
  }

  function findNewsContainer() {
    const selectors = [
      "[data-news-list]",
      "#news-list",
      "#newsList",
      "#articles",
      "#article-list",
      ".news-list",
      ".article-list",
      ".articles-grid",
      ".news-grid",
      "main"
    ];

    for (const s of selectors) {
      const el = document.querySelector(s);
      if (el) return el;
    }

    const root = document.createElement("section");
    root.id = "newsPatchRoot";
    root.style.maxWidth = "1120px";
    root.style.margin = "24px auto";
    root.style.padding = "0 16px";
    document.body.appendChild(root);
    return root;
  }

  function formatDate(value) {
    if (!value) return "";
    const d = new Date(value);
    if (Number.isNaN(d.getTime())) return "";
    return new Intl.DateTimeFormat("ko-KR", {
      year: "numeric",
      month: "2-digit",
      day: "2-digit",
      hour: "2-digit",
      minute: "2-digit"
    }).format(d);
  }

  function escapeHtml(s) {
    return String(s || "").replace(/[&<>"']/g, (ch) => ({
      "&": "&amp;",
      "<": "&lt;",
      ">": "&gt;",
      '"': "&quot;",
      "'": "&#39;"
    }[ch]));
  }

  function renderEmpty(container, category, message) {
    container.innerHTML = `
      <section class="news-patch-panel">
        <div class="news-patch-header">
          <h2>${escapeHtml(CATEGORY_LABELS[category] || category)}</h2>
          <p class="news-patch-muted">${escapeHtml(message || "표시할 기사가 없습니다.")}</p>
        </div>
      </section>
    `;
  }

  function renderLoading(container, category) {
    container.innerHTML = `
      <section class="news-patch-panel">
        <div class="news-patch-header">
          <h2>${escapeHtml(CATEGORY_LABELS[category] || category)}</h2>
          <p class="news-patch-muted">기사 데이터를 불러오는 중입니다...</p>
        </div>
      </section>
    `;
  }

  function renderArticles(container, category, payload) {
    const articles = Array.isArray(payload?.articles) ? payload.articles : [];
    const label = CATEGORY_LABELS[category] || category;

    if (!articles.length) {
      renderEmpty(
        container,
        category,
        `${label} 결과가 없습니다. GitHub Actions의 Collect BNCP News 실행 결과와 data/${category}-news.json 파일을 확인하세요.`
      );
      return;
    }

    const cards = articles.map((item) => `
      <article class="news-patch-card">
        <a class="news-patch-title" href="${escapeHtml(item.url)}" target="_blank" rel="noopener noreferrer">
          ${escapeHtml(item.title)}
        </a>
        <div class="news-patch-meta">
          <span>${escapeHtml(item.source || "출처 미상")}</span>
          <span>${escapeHtml(formatDate(item.publishedAt))}</span>
          ${item.query ? `<span class="news-patch-query">${escapeHtml(item.query)}</span>` : ""}
        </div>
        ${item.description ? `<p class="news-patch-desc">${escapeHtml(item.description)}</p>` : ""}
      </article>
    `).join("");

    container.innerHTML = `
      <section class="news-patch-panel">
        <div class="news-patch-header">
          <h2>${escapeHtml(label)}</h2>
          <p class="news-patch-muted">
            ${articles.length}건 · 업데이트 ${escapeHtml(formatDate(payload.generatedAt))}
          </p>
        </div>
        <div class="news-patch-list">${cards}</div>
      </section>
    `;
  }

  async function loadCategory(category) {
    const container = findNewsContainer();
    renderLoading(container, category);

    const url = CATEGORY_FILES[category];
    if (!url) {
      renderEmpty(container, category, "알 수 없는 카테고리입니다.");
      return;
    }

    try {
      const res = await fetch(`${url}?v=${Date.now()}`, { cache: "no-store" });
      if (!res.ok) throw new Error(`HTTP ${res.status}`);
      const payload = await res.json();
      console.info("[BNCP News]", category, payload);
      renderArticles(container, category, payload);
    } catch (err) {
      console.error("[BNCP News] failed to load", category, err);
      renderEmpty(
        container,
        category,
        `뉴스 데이터를 불러오지 못했습니다. ${url} 파일이 업로드되어 있는지 확인하세요. 오류: ${err.message || err}`
      );
    }
  }

  function installStyles() {
    if (document.getElementById("newsPatchStyle")) return;
    const style = document.createElement("style");
    style.id = "newsPatchStyle";
    style.textContent = `
      .news-patch-panel {
        width: 100%;
        box-sizing: border-box;
      }
      .news-patch-header {
        margin-bottom: 16px;
      }
      .news-patch-header h2 {
        margin: 0 0 6px 0;
        font-size: 24px;
        font-weight: 800;
      }
      .news-patch-muted {
        color: #6b7280;
        margin: 0;
        font-size: 14px;
      }
      .news-patch-list {
        display: grid;
        gap: 12px;
      }
      .news-patch-card {
        border: 1px solid rgba(17, 24, 39, 0.12);
        border-radius: 14px;
        padding: 16px;
        background: #fff;
        box-shadow: 0 6px 18px rgba(17, 24, 39, 0.06);
      }
      .news-patch-title {
        display: block;
        color: #111827;
        text-decoration: none;
        font-size: 17px;
        line-height: 1.45;
        font-weight: 800;
      }
      .news-patch-title:hover {
        text-decoration: underline;
      }
      .news-patch-meta {
        display: flex;
        flex-wrap: wrap;
        gap: 8px;
        margin-top: 8px;
        color: #6b7280;
        font-size: 13px;
      }
      .news-patch-meta span:not(:last-child)::after {
        content: "";
      }
      .news-patch-query {
        color: #f37321;
        font-weight: 700;
      }
      .news-patch-desc {
        margin: 10px 0 0 0;
        color: #374151;
        font-size: 14px;
        line-height: 1.55;
      }
    `;
    document.head.appendChild(style);
  }

  function attachButtonHandlers() {
    installStyles();

    const buttons = getAllCandidateButtons();
    let attached = 0;

    for (const btn of buttons) {
      const category = detectCategory(btn);
      if (!category) continue;

      btn.setAttribute("data-news-category", category);
      btn.addEventListener("click", function (e) {
        e.preventDefault();
        e.stopPropagation();
        loadCategory(category);
      }, true);
      attached++;
    }

    console.info(`[BNCP News] attached to ${attached} category buttons.`);

    // Auto-load domestic if URL has ?category=domestic or #domestic
    const params = new URLSearchParams(location.search);
    const requested = params.get("category") || location.hash.replace("#", "");
    if (CATEGORY_FILES[requested]) {
      loadCategory(requested);
    }
  }

  if (document.readyState === "loading") {
    document.addEventListener("DOMContentLoaded", attachButtonHandlers);
  } else {
    attachButtonHandlers();
  }

  window.BNCPNewsPatch = { loadCategory };
})();
